const purchases = $input.all();

// 1. Ta table officielle des actifs suivis
const assets = [
  { ticker: "3ZU0",     name: "AST SpaceMobile" },
  { ticker: "BKSY",     name: "Blacksky" },
  { ticker: "AMZ",     name: "Amazon" },
  { ticker: "APC",     name: "Apple" },
  { ticker: "BTC-USD",  name: "Bitcoin" },
  { ticker: "TL0",     name: "Tesla" },
  { ticker: "NVD",     name: "Nvidia" },
  { ticker: "ABEA",    name: "Alphabet" },
  { ticker: "TKE",     name: "Take-Two" },
  { ticker: "SU.PA",    name: "Schneider Electric" },
  { ticker: "AP2",     name: "Applied Materials" },
  { ticker: "1170",     name: "Arista Networks" },
  { ticker: "SOI.PA",   name: "Soitec" },
  { ticker: "ALRIB.PA", name: "Riber" },
  { ticker: "AL2SI.PA", name: "2CRSI" },
  { ticker: "GOLD.PA",  name: "Amundi Gold" },
  { ticker: "CSPX.AS",  name: "iShares S&P 500" },
  { ticker: "CNDX.AS",  name: "iShares NASDAQ 100" },
  { ticker: "EUEA.PA",  name: "iShares EURO STOXX 50" },
  { ticker: "STEC",  name: "iShares STOXX Europe 600 Tech" },
  { ticker: "ESE.PA",   name: "BNP Paribas Easy S&P 500" }
];

// 2. Ton dictionnaire Yahoo Finance
const yahooMap = {
  'APC': 'APC.F', 'AMZ': 'AMZ.F', 'NVD': 'NVD.F', 'AP2': 'AP2.DE', 'MSF': 'MSF.F',
  'TL0': 'TL0.DE', 'TLO': 'TL0.DE', 'TKE': 'TKE.F', 'M4I': 'M4I.F', 'ABEA': 'ABEA.F',
  'CSPX': 'CSPX.AS', 'CNDX': 'CNDX.AS', '3ZU0': '3ZU0.F', '1170': '1170.F',
  '9D5': '9D5.F', 'GXG': 'GXG.F', 'BKSY': 'BKSY',
  'GOLD-ETFP': 'GOLD-EUR.PA', // Attention : ta table dit GOLD.PA, ton achat dit GOLD-EUR.PA
  'AL2SI': 'AL2SI.PA', 'SU': 'SU.PA', 'ESE': 'ESE.PA',
  'EUEA': 'EUEA.AS', 'STEC': 'STEC.AS', 'ALRIB': 'ALRIB.PA',
  'SOI': 'SOI.PA', 'BTC': 'BTC-EUR' // Attention : ta table dit BTC-USD, ton achat dit BTC-EUR
};

// 3. Fonction pour trouver automatiquement le bon nom propre depuis ta table assets
function getAssetName(yahooTicker, shortTicker) {
  // On cherche une correspondance exacte sur le ticker Yahoo
  let found = assets.find(a => a.ticker.toLowerCase() === yahooTicker.toLowerCase());

  // Si pas trouvé (cas particuliers comme l'or ou le bitcoin qui ont des suffixes Yahoo différents),
  // on cherche si le début du ticker ou le shortTicker matche
  if (!found) {
    const baseYahoo = yahooTicker.split('.')[0].split('-')[0].toLowerCase(); // ex: "gold" ou "btc"
    found = assets.find(a => 
      a.ticker.toLowerCase().startsWith(baseYahoo) || 
      a.ticker.toLowerCase() === shortTicker.toLowerCase()
    );
  }

  // Si trouvé on renvoie le nom officiel, sinon le short ticker par défaut
  return found ? found.name : shortTicker;
}

// 4. Initialisation de reverseMap avec les paires de yahooMap
const reverseMap = {};
for (const [short, yahoo] of Object.entries(yahooMap)) {
  reverseMap[yahoo] = { 
    ticker: short, 
    name: getAssetName(yahoo, short) 
  };
}

// 5. Calcul des quantités nettes des achats
const netQty = {};
for (const item of purchases) {
    const ticker = (item.json.ticker || '').toUpperCase().trim();
    const qty = parseFloat(item.json.quantity) || 0;
    if (!ticker || ticker.startsWith('CASH-')) continue;
    netQty[ticker] = (netQty[ticker] || 0) + qty;
}

// 6. Génération de la liste finale des tickers et enrichissement de reverseMap
const tickers = [];
for (const [ticker, qty] of Object.entries(netQty)) {
    if (qty < 0.01) continue;
    const yahooTicker = yahooMap[ticker] || ticker;

    if (!reverseMap[yahooTicker]) {
      reverseMap[yahooTicker] = { 
        ticker: ticker, 
        name: getAssetName(yahooTicker, ticker) 
      };
    }
    if (!tickers.includes(yahooTicker)) tickers.push(yahooTicker);
}

const batch = tickers.slice(0, 20);
const allTickers = batch.join(',');

return [{ json: { allTickers, reverseMap } }];

const reverseMap = $('Build Tickers').first().json.reverseMap;
const sparkData = $input.first().json;
const pricesObj = {};

if (sparkData?.spark?.result) {
    for (const res of sparkData.spark.result) {
        if (!res?.response?.[0]?.meta) continue;

        const yahooTicker = res.symbol; // Reste la clé principale (ex: "3ZU0.F")

        const shortTicker = (reverseMap[yahooTicker] && reverseMap[yahooTicker].ticker) 
                            || yahooTicker;

        const shortName = (reverseMap[yahooTicker] && reverseMap[yahooTicker].name)
                          || shortTicker;

        const meta = res.response[0].meta;
        const price = meta.regularMarketPrice || 0;
        const previousClose = meta.chartPreviousClose || meta.previousClose || price;
        const currency = meta.currency || 'EUR';
        const dayChangePct = previousClose > 0 ? ((price - previousClose) / previousClose * 100) : 0;

        // On garde yahooTicker comme clé pour ne pas casser l'update Firestore
        pricesObj[yahooTicker] = { 
            ticker: shortTicker, // "3ZU0" reste dispo ici
            price, 
            previousClose, 
            currency, 
            dayChangePct, 
            shortName, // "Arista Networks" reste dispo ici
            lastUpdated: Date.now() 
        };
    }
}

return [{ json: {
    prices: pricesObj,
    metadata: {
        lastRefreshTimestamp: Date.now(),
        lastRefreshDevice: 'n8n-auto',
        tickerCount: Object.keys(pricesObj).length
    },
    summary: null
}}];

const prices = $('Parse Prices').first().json.prices;
const storedDoc = $input.first().json || {};

const rawThresholds = storedDoc.alertData || {};

const thresholds = {};
for (const [key, val] of Object.entries(rawThresholds)) {
    if (val && typeof val === 'object' && val.threshold !== undefined) {
        thresholds[key] = val;
    }
}

const today = new Date();
today.setHours(0, 0, 0, 0);
const todayTs = today.getTime();
const currentThresholds = {};
for (const [ticker, stored] of Object.entries(thresholds)) {
    if (stored.lastAlertedAt >= todayTs) {
        currentThresholds[ticker] = stored;
    }
}

const alerts = [];
const newThresholds = { ...currentThresholds };

for (const [ticker, data] of Object.entries(prices)) {
    const pct = data.dayChangePct || 0;
    const absPct = Math.abs(pct);
    if (absPct < 1) continue;

    const stored = currentThresholds[ticker] || null;
    const direction = pct >= 0 ? 'up' : 'down';

    if (!stored) {
        alerts.push({ ticker, pct, price: data.price, currency: data.currency || 'EUR' });
        newThresholds[ticker] = { threshold: absPct, direction, lastAlertedAt: Date.now() };
    } else {
        const sameDirection = (pct >= 0) === (stored.direction === 'up');
        if (sameDirection && absPct >= stored.threshold + 1) {
            alerts.push({ ticker, pct, price: data.price, currency: data.currency || 'EUR' });
            newThresholds[ticker] = { threshold: absPct, direction, lastAlertedAt: Date.now() };
        }
    }
}

return [{ json: {
    hasAlerts: alerts.length > 0,
    alerts,
    newThresholds
}}];

const { alerts } = $input.first().json;

const lines = alerts.map(a => {
    const emoji = a.pct >= 0 ? '🟢' : '🔴';
    const sign = a.pct >= 0 ? '+' : '';
    return `${emoji} *${a.ticker}* : ${sign}${a.pct.toFixed(2)}% (${a.price.toFixed(2)} ${a.currency})`;
}).join('\n');

const message = `📊 *Alerte Prix Portefeuille*\n\n${lines}\n\n_Prochain alerte si +1% supplémentaire_`;

return [{ json: { chatId: '2089017736', message } }];
